import { useEffect, useState, useContext } from "react";
import { AuthContext } from "./AuthContext";
import EventHeader from "./EventHeader";
import "../styles/events.css";

export default function EventPage() {
    const { user } = useContext(AuthContext);

    const [event, setEvent] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState("");

    const [rsvp, setRsvp] = useState(null);
    const [counts, setCounts] = useState({ going: 0, maybe: 0 });

    const [showAttendees, setShowAttendees] = useState(false);
    const [attendeeStatus, setAttendeeStatus] = useState("GOING");
    const [attendees, setAttendees] = useState([]);
    const [attendeesLoading, setAttendeesLoading] = useState(false);

    const eventId = (() => {
        const m = (window.location.hash || "").match(/^#\/events\/(\d+)/);
        return m ? Number(m[1]) : null;
    })();

    /* =====================
       FETCH EVENT
    ===================== */
    useEffect(() => {
        if (!eventId) return;

        fetch(`/api/events/${eventId}`)
            .then(r => {
                if (!r.ok) throw new Error("Event not found");
                return r.json();
            })
            .then(setEvent)
            .catch(e => setError(e.message))
            .finally(() => setLoading(false));
    }, [eventId]);

    /* =====================
       FETCH RSVP + COUNTS
    ===================== */
    useEffect(() => {
        if (!eventId || !user) return;

        fetch(`/api/events/${eventId}/rsvp?requesterEmail=${encodeURIComponent(user.email)}`)
            .then(r => r.json())
            .then(d => setRsvp(d.status || null))
            .catch(() => {});

        fetch(`/api/events/${eventId}/attendance`)
            .then(r => r.json())
            .then(setCounts)
            .catch(() => {});
    }, [eventId, user]);

    /* =====================
       RSVP ACTIONS
    ===================== */
    const sendRSVP = async (status) => {
        await fetch(
            `/api/events/${eventId}/rsvp?requesterEmail=${encodeURIComponent(user.email)}&status=${status}`,
            { method: "POST" }
        );
        setRsvp(status);
        setCounts(await fetch(`/api/events/${eventId}/attendance`).then(r => r.json()));
    };

    const cancelRSVP = async () => {
        await fetch(
            `/api/events/${eventId}/rsvp?requesterEmail=${encodeURIComponent(user.email)}`,
            { method: "DELETE" }
        );
        setRsvp(null);
        setCounts(await fetch(`/api/events/${eventId}/attendance`).then(r => r.json()));
    };

    /* =====================
       ATTENDEES
    ===================== */
    const openAttendees = async (status) => {
        setAttendeeStatus(status);
        setShowAttendees(true);
        setAttendeesLoading(true);

        try {
            const data = await fetch(`/api/events/${eventId}/attendees?status=${status}`).then(r => r.json());
            setAttendees(Array.isArray(data) ? data : []);
        } finally {
            setAttendeesLoading(false);
        }
    };

    if (loading) return <div className="event-page">Loading…</div>;
    if (error || !event) return <div className="event-page">{error || "Event not found"}</div>;

    return (
        <main className="event-page">
            <EventHeader
                event={event}
                activeTab="overview"
                rsvp={rsvp}
                onRSVP={sendRSVP}
                onCancelRSVP={cancelRSVP}
            />

            <section className="event-content">
                <div className="event-actions">
                    <button onClick={() => openAttendees("GOING")}>
                        View Going ({counts.going})
                    </button>
                    <button onClick={() => openAttendees("MAYBE")}>
                        View Maybe ({counts.maybe})
                    </button>
                </div>
            </section>

            {showAttendees && (
                <div className="modal-backdrop" onClick={() => setShowAttendees(false)}>
                    <div className="modal-card" onClick={e => e.stopPropagation()}>
                        <header className="modal-header">
                            <h3>{attendeeStatus === "GOING" ? "Going" : "Maybe"} Attendees</h3>
                            <button onClick={() => setShowAttendees(false)}>✕</button>
                        </header>

                        <div className="modal-tabs">
                            <button
                                className={attendeeStatus === "GOING" ? "active" : ""}
                                onClick={() => openAttendees("GOING")}
                            >
                                Going
                            </button>
                            <button
                                className={attendeeStatus === "MAYBE" ? "active" : ""}
                                onClick={() => openAttendees("MAYBE")}
                            >
                                Maybe
                            </button>
                        </div>

                        <div className="modal-body">
                            {attendeesLoading ? (
                                <div className="muted">Loading…</div>
                            ) : attendees.length === 0 ? (
                                <div className="muted">No attendees yet.</div>
                            ) : (
                                attendees.map(a => (
                                    <div key={a.id} className="attendee-row">
                                        <div className="avatar">
                                            {a.username[0].toUpperCase()}
                                        </div>
                                        <div className="name">{a.username}</div>
                                    </div>
                                ))
                            )}
                        </div>
                    </div>
                </div>
            )}
        </main>
    );
}
